@app.route('/saml/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')
    saml_request = request.form.get('SAMLRequest')
    relay_state = request.form.get('RelayState')
    
    user = USERS_DB.get(username)
    if not user or user['password'] != password:
        return render_template_string(LOGIN_PAGE, saml_request=saml_request, relay_state=relay_state, error="Invalid credentials")
    
    try:
        decoded_request = base64.b64decode(saml_request)
        
        import zlib
        try:
            inflated_request = zlib.decompress(decoded_request, -15)
        except:
            inflated_request = decoded_request
        
        root = etree.fromstring(inflated_request)
        
        acs_url = root.get('AssertionConsumerServiceURL')
        request_id = root.get('ID')
        
        issuer_elem = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
        sp_entity_id = issuer_elem.text if issuer_elem is not None else acs_url
        
    except Exception as e:
        return f"Error parsing SAML request: {str(e)}", 400
    
    saml_response = create_saml_response(
        user_email=username,
        sp_acs_url=acs_url,
        sp_entity_id=sp_entity_id,
        relay_state=relay_state,
        in_response_to=request_id
    )
    
    if not saml_response:
        return "Error generating SAML response", 500
    
    html_form = f'''
    <!DOCTYPE html>
    <html>
    <head><title>SAML Response</title></head>
    <body onload="document.forms[0].submit()">
        <form method="POST" action="{acs_url}">
            <input type="hidden" name="SAMLResponse" value="{saml_response}">
            <input type="hidden" name="RelayState" value="{relay_state or ''}">
            <noscript>
                <button type="submit">Continue</button>
            </noscript>
        </form>
    </body>
    </html>
    '''
    
    return html_form

